17	protocol GapsRepository {
18	    func fetchGaps(deviceId: String, start: Date) async -> [DateInterval]
19	}
20	
21	final class GapsRepositoryImpl: GapsRepository {
22	
23	    @Injected(\.eventsDatabaseManager) private var databaseManager
24	
25	    func fetchGaps(deviceId: String, start: Date) async -> [DateInterval] {
26	        let events = await databaseManager.fetchEvents(
27	            deviceId: deviceId,
28	            start: start,
29	            types: [.powerOn, .powerOff, .lowBatteryPowerOff]
30	        )
31	
32	        var gaps: [DateInterval] = []
33	        var offDate: Date? = nil
34	        
35	        // Если первое событие — powerOn, значит до него был разрыв от start
36	        if case .powerOn = events.first?.eventId {
37	            offDate = start
38	        }
39	        
40	        for (date, eventId) in events {
41	              switch eventId {
42	              case .powerOn:
43	                  guard let off = offDate else { continue }
44	                  gaps.append(DateInterval(start: off, end: date))
45	                  offDate = nil
46	              case .powerOff, .lowBatteryPowerOff:
47	                  offDate = date
48	              default:
49	                  break
50	              }
51	          }
52	
53	        return gaps
54	    }
55	}
