8	import Foundation
9	
10	protocol PendingTask: AnyObject {
11	    var label: String? { get }
12	    var isCancelled: Bool { get set }
13	
14	    func execute() async
15	    func cancel()
16	}
17	
18	final class TaskQueue {
19	    
20	    private class AsyncTask<T>: PendingTask {
21	        
22	        let label: String?
23	        var isCancelled = false
24	
25	        let continuation: CheckedContinuation<T, Error>?
26	        let block: () async throws -> T
27	        
28	        init(label: String?, continuation: CheckedContinuation<T, Error>?, block: @escaping () async throws -> T) {
29	            self.label = label
30	            self.continuation = continuation
31	            self.block = block
32	        }
33	        
34	        func execute() async {
35	            guard !isCancelled else { return }
36	            do {
37	                let result = try await block()
38	                continuation?.resume(returning: result)
39	            } catch {
40	                continuation?.resume(throwing: error)
41	            }
42	        }
43	        
44	        func cancel() {
45	            continuation?.resume(throwing: CancellationError())
46	        }
47	    }
48	    
49	    private class StreamTask<T>: PendingTask {
50	        let label: String?
51	        var isCancelled = false
52	        
53	        let continuation: AsyncThrowingStream<T, Error>.Continuation
54	        let block: (AsyncThrowingStream<T, Error>.Continuation) -> Void
55	        
56	        init(label: String?, continuation: AsyncThrowingStream<T, Error>.Continuation, block: @escaping (AsyncThrowingStream<T, Error>.Continuation) -> Void) {
57	            self.label = label
58	            self.continuation = continuation
59	            self.block = block
60	        }
61	        
62	        func execute() async {
63	            guard !isCancelled else { return }
64	            do {
65	                for try await value in AsyncThrowingStream(T.self, block) {
66	                    continuation.yield(value)
67	                }
68	                continuation.finish()
69	            } catch {
70	                continuation.finish(throwing: error)
71	            }
72	        }
73	        
74	        func cancel() {
75	            continuation.finish(throwing: CancellationError())
76	        }
77	    }
78	    
79	    private let label: String?
80	    
81	    private var pendingTasksContinuation: AsyncStream<PendingTask>.Continuation
82	    private var pendingTasks: AsyncStream<PendingTask>
83	    private var scope: Task<Void,Never>?
84	    
85	    private var isClosed = false
86	
87	    private func initScope() {
88	        scope = Task {
89	            for await pendingTask in pendingTasks {
90	                guard !Task.isCancelled, !isClosed else {
91	                    pendingTask.cancel()
92	                    continue
93	                }
94	                await pendingTask.execute()
95	            }
96	            
97	            for await pendingTask in pendingTasks {
98	                pendingTask.cancel()
99	            }
100	        }
101	    }
102	    
103	    public init(label: String? = nil){
104	         self.label = label
105	         (pendingTasks, pendingTasksContinuation) = AsyncStream.makeStream()
106	         initScope()
107	     }
108	    
109	    public func close() {
110	        guard !isClosed else { return }
111	        isClosed = true
112	        scope?.cancel()
113	        pendingTasksContinuation.finish()
114	    }
115	    
116	    public func dispatch(label: String? = nil, block: @escaping () async throws -> Void) {
117	        guard !isClosed else { return }
118	        pendingTasksContinuation.yield(AsyncTask(label: label, continuation: nil, block: block))
119	    }
120	    
121	    public func dispatch<T>(label: String? = nil, block: @escaping () async throws -> T) async throws -> T {
122	        guard !isClosed else { throw CancellationError() }
123	
124	        var pendingTask: AsyncTask<T>?
125	        
126	        return try await withTaskCancellationHandler {
127	            try await withCheckedThrowingContinuation { continuation in
128	                let task = AsyncTask(label: label, continuation: continuation, block: block)
129	                pendingTask = task
130	                pendingTasksContinuation.yield(task)
131	            }
132	        } onCancel: { [weak pendingTask] in
133	            pendingTask?.isCancelled = true
134	        }
135	    }
136	    
137	    public func dispatchStream<T>(label: String? = nil, block: @escaping (AsyncThrowingStream<T, Error>.Continuation) -> Void) -> AsyncThrowingStream<T, Error> {
138	        AsyncThrowingStream<T, Error> { typedContinuation in
139	            guard !isClosed else {
140	                typedContinuation.finish(throwing: CancellationError())
141	                return
142	            }
143	            
144	            let task = StreamTask<T>(label: label, continuation: typedContinuation, block: block)
145	            pendingTasksContinuation.yield(task)
146	        }
147	    }
148	}
